function pick(a) { return a[Math.floor(Math.random() * a.length)]; }

async function deleteCol(name) {
  var snap = await db.collection(name).get();
  if (snap.empty) return 0;
  var batch = db.batch(); var c = 0; var t = 0;
  for (var i = 0; i < snap.docs.length; i++) {
    batch.delete(snap.docs[i].ref); c++; t++;
    if (c >= 490) { await batch.commit(); batch = db.batch(); c = 0; }
  }
  if (c > 0) await batch.commit();
  return t;
}

async function batchWrite(col, items, idFn) {
  var batch = db.batch(); var c = 0;
  for (var i = 0; i < items.length; i++) {
    var item = items[i];
    var id = idFn(item);
    var data = Object.assign({}, item);
    delete data.id;
    batch.set(db.collection(col).doc(id), data);
    c++;
    if (c >= 490) { await batch.commit(); batch = db.batch(); c = 0; process.stdout.write("."); }
  }
  if (c > 0) await batch.commit();
}

async function run() {
  console.log("STEP 1: Deleting old data...");
  console.log("  students: " + await deleteCol("students"));
  console.log("  payments: " + await deleteCol("payments"));
  console.log("  families: " + await deleteCol("Familias"));

  console.log("STEP 2: Uploading " + students.length + " students...");
  await batchWrite("students", students, function(s) { return String(s.legajo); });
  console.log(" OK");

  console.log("STEP 3: Uploading " + families.length + " families...");
  await batchWrite("Familias", families, function(f) { return f.id; });
  console.log(" OK");

  console.log("STEP 4: Uploading " + payments.length + " payments...");
  await batchWrite("payments", payments, function(p) { return p.id; });
  console.log(" OK");

  console.log("STEP 5: Setting rates...");
  await db.collection("config").doc("rates").set({ Jardin: 35000, Primaria: 45000, Secundaria: 52000 });
  console.log("  OK");

  console.log("STEP 6: Creating/linking auth accounts...");
  var created = 0, skipped = 0, errors = 0;
  for (var i = 0; i < families.length; i++) {
    var f = families[i];
    var pw = "almafuerte" + f.id.replace("FAM-", "");
    try {
      var ex = null;
      try { ex = await auth.getUserByEmail(f.email); } catch(e) {}
      var uid;
      if (ex) { uid = ex.uid; skipped++; }
      else { var u = await auth.createUser({ email: f.email, password: pw, displayName: f.responsable }); uid = u.uid; created++; }
      await db.collection("Familias").doc(f.id).update({ authUid: uid });
    } catch(e) { errors++; }
    if ((i+1) % 100 === 0) console.log("  " + (i+1) + "/" + families.length);
  }

  console.log("");
  console.log("STEP 7: Verifying...");
  var tf = await db.collection("Familias").doc("FAM-0001").get();
  if (tf.exists) {
    var td = tf.data();
    var tl = String(td.studentIds[0]);
    var ts = await db.collection("students").doc(tl).get();
    if (ts.exists) {
      var sd = ts.data();
      console.log("  FAM-0001: " + td.responsable);
      console.log("  Student " + tl + ": " + sd.nombre + " " + sd.apellido + " familiaId=" + sd.familiaId);
      console.log("  Match: " + (sd.familiaId === "FAM-0001"));
    }
  }

  var sc = (await db.collection("students").get()).size;
  var fc = (await db.collection("Familias").get()).size;
  var pc = (await db.collection("payments").get()).size;

  console.log("");
  console.log("=== DONE ===");
  console.log("  Students: " + sc);
  console.log("  Families: " + fc);
  console.log("  Payments: " + pc);
  console.log("  Auth created: " + created + " | skipped: " + skipped + " | errors: " + errors);
  console.log("  Password: almafuerte0001, almafuerte0002, etc.");
  process.exit(0);
}

run().catch(function(e) { console.error(e); process.exit(1); });
